const cleanupLegacyArticles = async () => {
  if (!legacySlugsToRemove.length) return;
  await db.delete(articles).where(inArray(articles.slug, legacySlugsToRemove));
};

const upsertMaterialArticle = async (seed) => {
  const existing = await db.query.articles.findFirst({
    where: eq(articles.slug, seed.slug),
  });

  const payload = {
    title: seed.title,
    slug: seed.slug,
    excerpt: seed.excerpt,
    content: seed.content,
    category: seed.category,
    tags: seed.tags,
    status: "PUBLISHED",
    relatedType: "NONE",
    relatedId: null,
    seoTitle: seed.seoTitle,
    seoDescription: seed.seoDescription,
    publishedAt: existing?.publishedAt || now(),
  };

  if (existing) {
    await db.update(articles).set(payload).where(eq(articles.id, existing.id));
    return { action: "updated", slug: seed.slug };
  }

  await db.insert(articles).values(payload);
  return { action: "created", slug: seed.slug };
};

async function seedMaterialArticles() {
  console.log(`Seeding ${materialArticleSeeds.length} material articles...`);
  await cleanupLegacyArticles();

  for (const seed of materialArticleSeeds) {
    const result = await upsertMaterialArticle(seed);
    console.log(`${result.action}: ${result.slug}`);
  }

  console.log("Material article sync completed.");
  process.exit(0);
}

seedMaterialArticles().catch((error) => {
  console.error("Material article seed failed:", error);
  process.exit(1);
});
